'use client';

import React from 'react';
import type {
  AgentTeachingAgentRecord,
  AgentTeachingChatSource,
} from '@/shared/contracts/agent-teaching';
import type { SimpleChatMessage } from '@/shared/contracts/chatbot';
import { Button, Textarea, Card } from '@/shared/ui/primitives.public';
import { FormSection, FormField } from '@/shared/ui/forms-and-actions.public';
import {
  LoadingState,
  CompactEmptyState,
  UI_CENTER_ROW_SPACED_CLASSNAME,
} from '@/shared/ui/navigation-and-layout.public';
import { cn } from '@/shared/utils/ui-utils';

export type ResolveCollectionFn = (id: string) => string;

export function AgentListItem(props: {
  agent: AgentTeachingAgentRecord;
  isSelected: boolean;
  onSelect: (id: string) => void;
  resolveCollectionName: ResolveCollectionFn;
}): React.JSX.Element {
  const { agent, isSelected, onSelect, resolveCollectionName } = props;
  const collectionNames = (agent.collectionIds ?? []).map(resolveCollectionName).join(', ');

  return (
    <Button
      variant='ghost'
      className={cn(
        'w-full flex-col items-start gap-1 rounded-md border p-3 text-left transition h-auto font-normal',
        isSelected
          ? 'border-emerald-500/40 bg-emerald-500/10 text-emerald-100 hover:bg-emerald-500/15'
          : 'border-border bg-card/40 text-gray-200 hover:bg-card/60'
      )}
      onClick={() => onSelect(agent.id)}
    >
      <div className='font-medium text-sm'>{agent.name}</div>
      <div className='text-[11px] text-gray-400'>
        LLM: {agent.llmModel} • Embed: {agent.embeddingModel}
      </div>
      <div className='text-[11px] text-gray-500'>
        Collections: {collectionNames.length > 0 ? collectionNames : '—'}
      </div>
    </Button>
  );
}

export function ChatMessageList(props: { messages: SimpleChatMessage[] }): React.JSX.Element {
  const { messages } = props;
  return (
    <div className='h-[360px] overflow-auto rounded-md border border-border bg-card/30 p-3 mt-4'>
      {messages.length === 0 ? (
        <div className='text-sm text-gray-400'>
          Start chatting. The server will embed your question, retrieve top sources, and answer with
          citations.
        </div>
      ) : (
        <div className='space-y-3'>
          {messages.map((msg: SimpleChatMessage, idx: number) => (
            <div key={`${msg.role}-${idx}`} className='space-y-1'>
              <div className='text-[11px] text-gray-500'>{msg.role}</div>
              <div className='whitespace-pre-wrap text-sm text-gray-200'>{msg.content}</div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

export function SourceCard(props: {
  src: AgentTeachingChatSource;
  resolveCollectionName: ResolveCollectionFn;
}): React.JSX.Element {
  const { src, resolveCollectionName } = props;
  const title = src.metadata?.title ?? '';
  return (
    <Card variant='subtle-compact' padding='sm' className='bg-card/50'>
      <div className='flex items-center justify-between gap-2'>
        <div className='text-xs text-gray-300'>
          [doc:{src.documentId}] • {resolveCollectionName(src.collectionId)}
        </div>
        <div className='text-[11px] text-gray-500'>score {src.score.toFixed(3)}</div>
      </div>
      {title.length > 0 && <div className='mt-1 text-[11px] text-gray-400'>Title: {title}</div>}
      <div className='mt-2 max-h-28 overflow-auto whitespace-pre-wrap text-xs text-gray-200'>
        {src.text}
      </div>
    </Card>
  );
}

export function AgentSidebar(props: {
  agents: AgentTeachingAgentRecord[];
  loadingAgents: boolean;
  selectedAgentId: string;
  setSelectedAgentId: (id: string) => void;
  resolveCollectionName: ResolveCollectionFn;
  setMessages: (msgs: SimpleChatMessage[]) => void;
  setLastSources: (sources: AgentTeachingChatSource[]) => void;
}): React.JSX.Element {
  const {
    agents,
    loadingAgents,
    selectedAgentId,
    setSelectedAgentId,
    resolveCollectionName,
    setMessages,
    setLastSources,
  } = props;

  if (loadingAgents) {
    return (
      <FormSection title='Learner Agents' className='p-4 lg:col-span-1 space-y-4'>
        <LoadingState message='Loading agents…' className='py-8' size='sm' />
      </FormSection>
    );
  }

  if (agents.length === 0) {
    return (
      <FormSection title='Learner Agents' className='p-4 lg:col-span-1 space-y-4'>
        <CompactEmptyState
          title='No agents'
          description='Create a learner agent first.'
          className='py-8'
        />
      </FormSection>
    );
  }

  return (
    <FormSection title='Learner Agents' className='p-4 lg:col-span-1 space-y-4'>
      <div className='space-y-2'>
        {agents.map((agent) => (
          <AgentListItem
            key={agent.id}
            agent={agent}
            isSelected={agent.id === selectedAgentId}
            resolveCollectionName={resolveCollectionName}
            onSelect={(id) => {
              setSelectedAgentId(id);
              setMessages([]);
              setLastSources([]);
            }}
          />
        ))}
      </div>
    </FormSection>
  );
}

export function ChatPane(props: {
  selectedAgent: AgentTeachingAgentRecord | null;
  messages: SimpleChatMessage[];
  setMessages: (msgs: SimpleChatMessage[]) => void;
  lastSources: AgentTeachingChatSource[];
  setLastSources: (sources: AgentTeachingChatSource[]) => void;
  sending: boolean;
  input: string;
  setInput: (val: string) => void;
  handleSend: () => void;
  resolveCollectionName: ResolveCollectionFn;
}): React.JSX.Element {
  const {
    selectedAgent,
    messages,
    setMessages,
    lastSources,
    setLastSources,
    sending,
    input,
    setInput,
    handleSend,
    resolveCollectionName,
  } = props;

  return (
    <FormSection
      title='Chat'
      description={
        selectedAgent !== null ? `Agent: ${selectedAgent.name}` : 'Select an agent to start'
      }
      className='p-4 lg:col-span-2 space-y-4'
    >
      <div className={cn(UI_CENTER_ROW_SPACED_CLASSNAME, 'justify-between')}>
        <div className='text-sm font-semibold text-white'>Chat</div>
        <Button
          type='button'
          variant='outline'
          onClick={() => {
            setMessages([]);
            setLastSources([]);
          }}
          disabled={sending || messages.length === 0}
        >
          Clear
        </Button>
      </div>

      <ChatMessageList messages={messages} />

      <FormField label='Message'>
        <Textarea
          value={input}
          onChange={(e) => setInput(e.target.value)}
          placeholder='Ask something that should be answered from your embedded knowledge…'
          className='min-h-[90px]'
          disabled={sending || selectedAgent === null}
          aria-label='Ask something that should be answered from your embedded knowledge…'
          title='Ask something that should be answered from your embedded knowledge…'
        />
        <div className='flex justify-end gap-2 mt-2'>
          <Button
            type='button'
            onClick={() => handleSend()}
            disabled={sending || selectedAgent === null || input.trim().length === 0}
            loading={sending}
            loadingText='Thinking…'
          >
            Send
          </Button>
        </div>
      </FormField>

      <FormSection title='Retrieved sources' variant='subtle' className='p-3'>
        {lastSources.length === 0 ? (
          <div className='mt-2 text-sm text-gray-400'>
            No sources retrieved yet (or below min score).
          </div>
        ) : (
          <div className='mt-2 space-y-2'>
            {lastSources.map((src) => (
              <SourceCard
                key={src.documentId}
                src={src}
                resolveCollectionName={resolveCollectionName}
              />
            ))}
          </div>
        )}
      </FormSection>
    </FormSection>
  );
}

import { PAGE_CONTEXT_ENGINE_VERSION } from '@/features/ai/ai-context-registry/context/page-context-shared';
import type {
  AgentTeachingAgentRecord,
  AgentTeachingChatSource,
  AgentTeachingEmbeddingCollectionRecord,
} from '@/shared/contracts/agent-teaching';
import type {
  ContextRegistryResolutionBundle,
  ContextRuntimeDocument,
  ContextRuntimeDocumentSection,
} from '@/shared/contracts/ai-context-registry';
import type { SimpleChatMessage } from '@/shared/contracts/chatbot';

export const AGENT_TEACHING_CHAT_CONTEXT_ROOT_IDS = [
  'page:agent-teaching-chat',
  'component:agent-teaching-chat-panel',
  'action:agent-teaching-chat',
  'collection:agent-teaching-agents',
  'collection:agent-teaching-embedding-collections',
] as const;

export const AGENT_TEACHING_CHAT_RUNTIME_REF = {
  id: 'runtime:agent-teaching-chat:workspace',
  kind: 'runtime_document' as const,
  providerId: 'agent-teaching-chat-local',
  entityType: 'agent_teaching_chat_state',
};

type BuildAgentTeachingChatContextBundleInput = {
  agents: AgentTeachingAgentRecord[];
  collections: AgentTeachingEmbeddingCollectionRecord[];
  chatModelId: string;
  embeddingModelId: string;
  selectedAgent: AgentTeachingAgentRecord | null;
  messages: SimpleChatMessage[];
  lastSources: AgentTeachingChatSource[];
};

const summarizeAgent = (
  agent: AgentTeachingAgentRecord,
  collectionNamesById: Map<string, string>
): Record<string, unknown> => ({
  id: agent.id,
  name: agent.name,
  llmModel: agent.llmModel,
  embeddingModel: agent.embeddingModel,
  enabled: agent.enabled ?? true,
  collectionIds: agent.collectionIds,
  collectionNames: (agent.collectionIds ?? []).map((id) => collectionNamesById.get(id) ?? id),
  retrievalTopK: agent.retrievalTopK ?? agent.topK ?? null,
  retrievalMinScore: agent.retrievalMinScore ?? agent.scoreThreshold ?? null,
});

const summarizeSource = (
  source: AgentTeachingChatSource,
  collectionNamesById: Map<string, string>
): Record<string, unknown> => ({
  documentId: source.documentId,
  collectionId: source.collectionId,
  collectionName: collectionNamesById.get(source.collectionId) ?? source.collectionId,
  score: source.score,
  title: source.metadata?.title ?? null,
  sourceType: source.metadata?.source ?? null,
  textPreview: (source.text ?? '').trim().slice(0, 600),
});

export const buildAgentTeachingChatRuntimeDocument = (
  input: BuildAgentTeachingChatContextBundleInput
): ContextRuntimeDocument => {
  const collectionNamesById = new Map(
    input.collections.map((collection) => [collection.id, collection.name])
  );

  const sections: ContextRuntimeDocumentSection[] = [
    {
      kind: 'facts',
      title: 'Workspace snapshot',
      items: [
      {
        selectedAgentId: input.selectedAgent?.id ?? null,
        selectedAgentName: input.selectedAgent?.name ?? null,
        agentCount: input.agents.length,
        collectionCount: input.collections.length,
        messageCount: input.messages.length,
        lastRetrievedSourceCount: input.lastSources.length,
        configuredChatModelId: input.chatModelId.length > 0 ? input.chatModelId : null,
        configuredEmbeddingModelId: input.embeddingModelId.length > 0 ? input.embeddingModelId : null,
      },
      ],
      },
      {
      kind: 'items',
      title: 'Available agents',
      summary: 'Current learner agents visible in the teaching workspace.',
      items: input.agents.slice(0, 12).map((agent) => summarizeAgent(agent, collectionNamesById)),
      },
      ];

      if (input.selectedAgent !== null) {
      sections.push({
      kind: 'facts',
      title: 'Selected agent',
      items: [summarizeAgent(input.selectedAgent, collectionNamesById)],
      });
      }

      if (input.messages.length > 0) {
      sections.push({
      kind: 'items',
      title: 'Recent messages',
      summary: 'Latest chat messages on the page.',
      items: input.messages.slice(-8).map((message, index) => ({
      index: input.messages.length - Math.min(input.messages.length, 8) + index,
      role: message.role,
      content: message.content,
      })),
      });
      }

      if (input.lastSources.length > 0) {
      sections.push({
      kind: 'items',
      title: 'Retrieved sources',
      summary: 'Latest knowledge-base sources shown in the teaching chat UI.',
      items: input.lastSources.slice(0, 8).map((source) => summarizeSource(source, collectionNamesById)),
      });
      }

      return {
      id: AGENT_TEACHING_CHAT_RUNTIME_REF.id,
      kind: 'runtime_document',
      entityType: AGENT_TEACHING_CHAT_RUNTIME_REF.entityType,
      title: input.selectedAgent !== null
      ? `Agent teaching chat state for ${input.selectedAgent.name}`
      : 'Agent teaching chat workspace state',
      summary:
      'Live operator context for the Agent Creator teaching chat page, including selected agent, ' +
      'recent messages, and retrieved knowledge-base source previews.',
      status: null,
      tags: ['agent-creator', 'teaching', 'chat', 'live-state'],
      relatedNodeIds: [...AGENT_TEACHING_CHAT_CONTEXT_ROOT_IDS],
      facts: {
      selectedAgentId: input.selectedAgent?.id ?? null,
      selectedAgentName: input.selectedAgent?.name ?? null,
      agentCount: input.agents.length,
      collectionCount: input.collections.length,
      messageCount: input.messages.length,
      lastRetrievedSourceCount: input.lastSources.length,
      configuredChatModelId: input.chatModelId.length > 0 ? input.chatModelId : null,
      configuredEmbeddingModelId: input.embeddingModelId.length > 0 ? input.embeddingModelId : null,
      },    sections,
    provenance: {
      source: 'agentcreator.teaching.chat.client-state',
      persisted: false,
    },
  };
};

export const buildAgentTeachingChatContextBundle = (
  input: BuildAgentTeachingChatContextBundleInput
): ContextRegistryResolutionBundle => ({
  refs: [AGENT_TEACHING_CHAT_RUNTIME_REF],
  nodes: [],
  documents: [buildAgentTeachingChatRuntimeDocument(input)],
  truncated: false,
  engineVersion: PAGE_CONTEXT_ENGINE_VERSION,
});

'use client';

import React, { useMemo, useState, useCallback } from 'react';

import type { AgentTeachingEmbeddingCollectionRecord } from '@/shared/contracts/agent-teaching';
import { internalError } from '@/shared/errors/app-error';
import { createStrictContext } from '@/shared/lib/react/createStrictContext';
import { useToast } from '@/shared/ui/primitives.public';

import { useAgentTeachingQueriesContext } from './AgentTeachingContext';
import {
  useDeleteEmbeddingCollectionMutation,
  useUpsertEmbeddingCollectionMutation,
} from '../hooks/useAgentTeachingQueries';
import { logClientError } from '@/shared/utils/observability/client-error-logger';

interface AgentTeachingCollectionsContextValue {
  collections: AgentTeachingEmbeddingCollectionRecord[];
  embeddingModels: string[];
  isLoading: boolean;
  isSaving: boolean;
  isDeleting: boolean;

  // Modal State
  isModalOpen: boolean;
  editingItem: AgentTeachingEmbeddingCollectionRecord | null;
  draft: Partial<AgentTeachingEmbeddingCollectionRecord>;
  setDraft: React.Dispatch<React.SetStateAction<Partial<AgentTeachingEmbeddingCollectionRecord>>>;

  // Delete State
  itemToDelete: AgentTeachingEmbeddingCollectionRecord | null;
  setItemToDelete: (item: AgentTeachingEmbeddingCollectionRecord | null) => void;

  // Actions
  openCreate: () => void;
  openEdit: (item: AgentTeachingEmbeddingCollectionRecord) => void;
  closeModal: () => void;
  handleSave: () => Promise<void>;
  handleDelete: () => Promise<void>;
  getUsedByCount: (collectionId: string) => number;
}

const {
  Context: AgentTeachingCollectionsContext,
  useStrictContext: useAgentTeachingCollectionsContext,
} = createStrictContext<AgentTeachingCollectionsContextValue>({
  hookName: 'useAgentTeachingCollectionsContext',
  providerName: 'AgentTeachingCollectionsProvider',
  displayName: 'AgentTeachingCollectionsContext',
  errorFactory: internalError,
});
export { useAgentTeachingCollectionsContext };

export function AgentTeachingCollectionsProvider({
  children,
}: {
  children: React.ReactNode;
}): React.JSX.Element {
  const { toast } = useToast();
  const { collections, agents, embeddingModelId, isLoading } = useAgentTeachingQueriesContext();

  const embeddingModels = useMemo(() => {
    const normalized = embeddingModelId.trim();
    if (normalized) return [normalized];
    return [];
  }, [embeddingModelId]);

  const { mutateAsync: upsert, isPending: isSaving } = useUpsertEmbeddingCollectionMutation();
  const { mutateAsync: remove, isPending: isDeleting } = useDeleteEmbeddingCollectionMutation();

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingItem, setEditingItem] = useState<AgentTeachingEmbeddingCollectionRecord | null>(
    null
  );
  const [draft, setDraft] = useState<Partial<AgentTeachingEmbeddingCollectionRecord>>({});
  const [itemToDelete, setItemToDelete] = useState<AgentTeachingEmbeddingCollectionRecord | null>(
    null
  );

  const openCreate = useCallback(() => {
    setEditingItem(null);
    setDraft({
      name: '',
      description: '',
      embeddingModel: embeddingModels[0] ?? '',
    });
    setIsModalOpen(true);
  }, [embeddingModels]);

  const openEdit = useCallback((item: AgentTeachingEmbeddingCollectionRecord) => {
    setEditingItem(item);
    setDraft({ ...item });
    setIsModalOpen(true);
  }, []);

  const closeModal = useCallback(() => {
    setIsModalOpen(false);
    setEditingItem(null);
    setDraft({});
  }, []);

  const handleSave = async () => {
    const name = draft.name?.trim();
    if (!name) {
      toast('Collection name is required.', { variant: 'error' });
      return;
    }
    const embeddingModel = editingItem
      ? editingItem.embeddingModel.trim()
      : embeddingModelId.trim() || draft.embeddingModel?.trim() || '';
    if (!embeddingModel) {
      toast('Configure Agent Teaching Embeddings in AI Brain first.', { variant: 'error' });
      return;
    }
    try {
      await upsert({
        ...(editingItem?.id ? { id: editingItem.id } : {}),
        name,
        description: typeof draft.description === 'string' ? draft.description : null,
        embeddingModel,
      });
      toast(editingItem ? 'Collection updated.' : 'Collection created.', { variant: 'success' });
      closeModal();
    } catch (error) {
      logClientError(error);
      toast(error instanceof Error ? error.message : 'Failed to save collection.', {
        variant: 'error',
      });
    }
  };

  const handleDelete = async () => {
    if (!itemToDelete) return;
    try {
      await remove({ id: itemToDelete.id });
      toast('Collection deleted.', { variant: 'success' });
    } catch (error) {
      logClientError(error);
      toast(error instanceof Error ? error.message : 'Failed to delete collection.', {
        variant: 'error',
      });
    } finally {
      setItemToDelete(null);
    }
  };

  const getUsedByCount = useCallback(
    (collectionId: string): number =>
      agents.filter((agent) => (agent.collectionIds ?? []).includes(collectionId)).length,
    [agents]
  );

  const value = useMemo(
    (): AgentTeachingCollectionsContextValue => ({
      collections,
      embeddingModels,
      isLoading,
      isSaving,
      isDeleting,
      isModalOpen,
      editingItem,
      draft,
      setDraft,
      itemToDelete,
      setItemToDelete,
      openCreate,
      openEdit,
      closeModal,
      handleSave,
      handleDelete,
      getUsedByCount,
    }),
    [
      collections,
      embeddingModels,
      isLoading,
      isSaving,
      isDeleting,
      isModalOpen,
      editingItem,
      draft,
      itemToDelete,
      openCreate,
      openEdit,
      closeModal,
      handleSave,
      handleDelete,
      getUsedByCount,
    ]
  );

  return (
    <AgentTeachingCollectionsContext.Provider value={value}>
      {children}
    </AgentTeachingCollectionsContext.Provider>
  );
}

'use client';

import { useParams } from 'next/navigation';
import { useState, useMemo, useCallback } from 'react';

import type {
  AgentTeachingChatSource,
  AgentTeachingEmbeddingDocumentListItem,
} from '@/shared/contracts/agent-teaching';
import { useToast } from '@/shared/ui/primitives.public';

import { useAgentTeachingQueriesContext } from '../context/AgentTeachingContext';
import {
  useAddEmbeddingDocumentMutation,
  useDeleteEmbeddingDocumentMutation,
  useEmbeddingDocuments,
  useSearchEmbeddingCollectionMutation,
} from '../hooks/useAgentTeachingQueries';
import { logClientError } from '@/shared/utils/observability/client-error-logger';


export function useAgentTeachingCollectionDetailState(): {
  collectionId: string | null;
  collection: AgentTeachingEmbeddingCollectionRecord | null;
  docs: AgentTeachingEmbeddingDocumentListItem[];
  isLoading: boolean;
  adding: boolean;
  deleting: boolean;
  searching: boolean;
  text: string;
  setText: React.Dispatch<React.SetStateAction<string>>;
  title: string;
  setTitle: React.Dispatch<React.SetStateAction<string>>;
  source: string;
  setSource: React.Dispatch<React.SetStateAction<string>>;
  tags: string;
  setTags: React.Dispatch<React.SetStateAction<string>>;
  docToDelete: AgentTeachingEmbeddingDocumentListItem | null;
  setDocToDelete: React.Dispatch<React.SetStateAction<AgentTeachingEmbeddingDocumentListItem | null>>;
  searchQuery: string;
  setSearchQuery: React.Dispatch<React.SetStateAction<string>>;
  searchTopK: number;
  setSearchTopK: React.Dispatch<React.SetStateAction<number>>;
  searchMinScore: number;
  setSearchMinScore: React.Dispatch<React.SetStateAction<number>>;
  searchResults: AgentTeachingChatSource[];
  setSearchResults: React.Dispatch<React.SetStateAction<AgentTeachingChatSource[]>>;
  searchError: string | null;
  setSearchError: React.Dispatch<React.SetStateAction<string | null>>;
  handleAdd: () => Promise<void>;
  handleDelete: () => Promise<void>;
  handleSearch: () => Promise<void>;
} {
  const { toast } = useToast();
  const params = useParams<{ collectionId: string }>();
  const collectionId = params.collectionId ?? null;

  const { collections, isLoading: loadingCollections } = useAgentTeachingQueriesContext();
  const collection = useMemo(
    () => (collectionId !== null ? (collections.find((c) => c.id === collectionId) ?? null) : null),
    [collectionId, collections]
  );

  const {
    data: docsResult,
    isLoading: loadingDocs,
    refetch: refetchDocs,
  } = useEmbeddingDocuments(collectionId);
  const { mutateAsync: addDoc, isPending: adding } = useAddEmbeddingDocumentMutation();
  const { mutateAsync: deleteDoc, isPending: deleting } = useDeleteEmbeddingDocumentMutation();
  const searchMutation = useSearchEmbeddingCollectionMutation();

  const [text, setText] = useState('');
  const [title, setTitle] = useState('');
  const [source, setSource] = useState('');
  const [tags, setTags] = useState('');
  const [docToDelete, setDocToDelete] = useState<AgentTeachingEmbeddingDocumentListItem | null>(
    null
  );
  const [searchQuery, setSearchQuery] = useState('');
  const [searchTopK, setSearchTopK] = useState(8);
  const [searchMinScore, setSearchMinScore] = useState(0.15);
  const [searchResults, setSearchResults] = useState<AgentTeachingChatSource[]>([]);
  const [searchError, setSearchError] = useState<string | null>(null);

  const isLoading = loadingCollections || loadingDocs;
  const searching = searchMutation.isPending;

  const handleAdd = useCallback(async () => {
    if (collectionId === null) return;
    const trimmed = text.trim();
    if (trimmed.length === 0) {
      toast('Text is required.', { variant: 'error' });
      return;
    }
    try {
      await addDoc({
        collectionId,
        text: trimmed,
        title: title.trim().length > 0 ? title.trim() : null,
        source: source.trim().length > 0 ? source.trim() : null,
        tags: tags
          .split(',')
          .map((t) => t.trim())
          .filter((t) => t.length > 0),
      });
      toast('Document embedded and saved.', { variant: 'success' });
      setText('');
      setTitle('');
      setSource('');
      setTags('');
      void refetchDocs();
    } catch (error) {
      logClientError(error);
      toast(error instanceof Error ? error.message : 'Failed to add document.', {
        variant: 'error',
      });
    }
  }, [collectionId, text, title, source, tags, addDoc, toast, refetchDocs]);

  const handleDelete = useCallback(async () => {
    if (collectionId === null || docToDelete === null) return;
    try {
      await deleteDoc({ collectionId, documentId: docToDelete.id });
      toast('Document deleted.', { variant: 'success' });
      void refetchDocs();
    } catch (error) {
      logClientError(error);
      toast(error instanceof Error ? error.message : 'Failed to delete document.', {
        variant: 'error',
      });
    } finally {
      setDocToDelete(null);
    }
  }, [collectionId, docToDelete, deleteDoc, toast, refetchDocs]);

  const handleSearch = useCallback(async () => {
    if (collectionId === null) return;
    const queryText = searchQuery.trim();
    if (queryText.length === 0) return;
    setSearchError(null);
    try {
      const results = await searchMutation.mutateAsync({
        collectionId,
        queryText,
        topK: searchTopK,
        minScore: searchMinScore,
      });
      setSearchResults(results);
    } catch (error) {
      logClientError(error);
      setSearchError(error instanceof Error ? error.message : 'Search failed.');
      setSearchResults([]);
    }
  }, [collectionId, searchQuery, searchTopK, searchMinScore, searchMutation]);

  const docs = useMemo(() => docsResult?.items ?? [], [docsResult]);

  return {
    collectionId,
    collection,
    docs,
    isLoading,
    adding,
    deleting,
    searching,
    text,
    setText,
    title,
    setTitle,
    source,
    setSource,
    tags,
    setTags,
    docToDelete,
    setDocToDelete,
    searchQuery,
    setSearchQuery,
    searchTopK,
    setSearchTopK,
    searchMinScore,
    setSearchMinScore,
    searchResults,
    searchError,
    handleAdd,
    handleDelete,
    handleSearch,
  };
}

'use client';

import { useMemo, useState, useCallback } from 'react';

import type {
  AgentTeachingAgentRecord,
  AgentTeachingEmbeddingCollectionRecord,
} from '@/shared/contracts/agent-teaching';
import { useToast } from '@/shared/ui/primitives.public';

import { useAgentTeachingQueriesContext } from '../context/AgentTeachingContext';
import {
  useDeleteEmbeddingCollectionMutation,
  useUpsertEmbeddingCollectionMutation,
} from '../hooks/useAgentTeachingQueries';
import { logClientError } from '@/shared/utils/observability/client-error-logger';


export function useAgentTeachingCollectionsState() {
  const { toast } = useToast();
  const { collections, agents, embeddingModelId, isLoading } = useAgentTeachingQueriesContext();
  const embeddingModels = useMemo(() => {
    const normalized = embeddingModelId.trim();
    if (normalized) return [normalized];
    return [];
  }, [embeddingModelId]);

  const { mutateAsync: upsert, isPending: saving } = useUpsertEmbeddingCollectionMutation();
  const { mutateAsync: remove, isPending: deleting } = useDeleteEmbeddingCollectionMutation();

  const [modalOpen, setModalOpen] = useState(false);
  const [editing, setEditing] = useState<AgentTeachingEmbeddingCollectionRecord | null>(null);
  const [draft, setDraft] = useState<Partial<AgentTeachingEmbeddingCollectionRecord>>({});
  const [itemToDelete, setItemToDelete] = useState<AgentTeachingEmbeddingCollectionRecord | null>(
    null
  );

  const openCreate = useCallback(() => {
    setEditing(null);
    setDraft({
      name: '',
      description: '',
      embeddingModel: embeddingModels[0] ?? '',
    });
    setModalOpen(true);
  }, [embeddingModels]);

  const openEdit = useCallback((item: AgentTeachingEmbeddingCollectionRecord) => {
    setEditing(item);
    setDraft({ ...item });
    setModalOpen(true);
  }, []);

  const closeModal = useCallback(() => {
    setModalOpen(false);
    setEditing(null);
    setDraft({});
  }, []);

  const handleSave = async () => {
    const name = draft.name?.trim();
    if (!name) {
      toast('Collection name is required.', { variant: 'error' });
      return;
    }
    const embeddingModel = draft.embeddingModel?.trim();
    if (!embeddingModel) {
      toast('Embedding model is required.', { variant: 'error' });
      return;
    }
    try {
      await upsert({
        ...(editing?.id ? { id: editing.id } : {}),
        name,
        description: typeof draft.description === 'string' ? draft.description : null,
        embeddingModel,
      });
      toast(editing ? 'Collection updated.' : 'Collection created.', { variant: 'success' });
      closeModal();
    } catch (error) {
      logClientError(error);
      toast(error instanceof Error ? error.message : 'Failed to save collection.', {
        variant: 'error',
      });
    }
  };

  const handleDelete = async () => {
    if (!itemToDelete) return;
    try {
      await remove({ id: itemToDelete.id });
      toast('Collection deleted.', { variant: 'success' });
    } catch (error) {
      logClientError(error);
      toast(error instanceof Error ? error.message : 'Failed to delete collection.', {
        variant: 'error',
      });
    } finally {
      setItemToDelete(null);
    }
  };

  const usedByCount = useCallback(
    (collectionId: string): number =>
      agents.filter((agent: AgentTeachingAgentRecord) =>
        (agent.collectionIds ?? []).includes(collectionId)
      ).length,
    [agents]
  );

  return {
    collections,
    agents,
    embeddingModels,
    isLoading,
    saving,
    deleting,
    modalOpen,
    setModalOpen,
    editing,
    draft,
    setDraft,
    itemToDelete,
    setItemToDelete,
    openCreate,
    openEdit,
    closeModal,
    handleSave,
    handleDelete,
    usedByCount,
  };
}

'use client';

import React from 'react';

import type {
  AgentTeachingAgentRecord,
  AgentTeachingEmbeddingCollectionRecord,
} from '@/shared/contracts/agent-teaching';
import { AdminAgentTeachingBreadcrumbs } from '@/shared/ui/admin.public';
import { ItemLibrary } from '@/shared/ui/data-display.public';
import { useToast } from '@/shared/ui/primitives.public';

import { LearnerAgentForm, type LearnerAgentLibraryItem } from '../components/LearnerAgentForm';
import { useAgentTeachingQueriesContext } from '../context/AgentTeachingContext';
import {
  useDeleteTeachingAgentMutation,
  useUpsertTeachingAgentMutation,
} from '../hooks/useAgentTeachingQueries';
import { logClientError } from '@/shared/utils/observability/client-error-logger';


export function AgentTeachingAgentsPage(): React.JSX.Element {
  const { toast } = useToast();
  const {
    agents,
    collections,
    chatModelId,
    embeddingModelId,
    isLoading: isLoadingContext,
  } = useAgentTeachingQueriesContext();

  const { mutateAsync: upsert, isPending: saving } = useUpsertTeachingAgentMutation();
  const { mutateAsync: remove } = useDeleteTeachingAgentMutation();
  const libraryAgents = React.useMemo<LearnerAgentLibraryItem[]>(
    () =>
      agents.map((agent: AgentTeachingAgentRecord) => ({
        ...agent,
        description: typeof agent.description === 'string' ? agent.description : null,
      })),
    [agents]
  );

  const handleSave = async (draft: Partial<LearnerAgentLibraryItem>): Promise<void> => {
    const name = draft.name?.trim();
    if (!name) {
      toast('Agent name is required.', { variant: 'error' });
      return;
    }
    const llmModel = chatModelId.trim();
    if (!llmModel) {
      toast('Configure Agent Teaching Chat in AI Brain first.', { variant: 'error' });
      return;
    }
    const embeddingModel = embeddingModelId.trim();
    if (!embeddingModel) {
      toast('Configure Agent Teaching Embeddings in AI Brain first.', { variant: 'error' });
      return;
    }

    const selectedCollectionIds = Array.isArray(draft.collectionIds) ? draft.collectionIds : [];
    const mismatchedCollections = selectedCollectionIds
      .map((id: string) =>
        collections.find((c: AgentTeachingEmbeddingCollectionRecord) => c.id === id)
      )
      .filter(
        (
          c: AgentTeachingEmbeddingCollectionRecord | undefined
        ): c is AgentTeachingEmbeddingCollectionRecord => Boolean(c)
      )
      .filter((c: AgentTeachingEmbeddingCollectionRecord) => c.embeddingModel !== embeddingModel);
    if (mismatchedCollections.length > 0) {
      toast(
        `Embedding model mismatch: ${mismatchedCollections
          .map((c: AgentTeachingEmbeddingCollectionRecord) => c.name)
          .join(', ')}`,
        { variant: 'error' }
      );
      return;
    }

    try {
      const temperatureRaw = typeof draft.temperature === 'number' ? draft.temperature : 0.2;
      const temperature = Number.isFinite(temperatureRaw)
        ? Math.max(0, Math.min(temperatureRaw, 2))
        : 0.2;
      const maxTokensRaw = typeof draft.maxTokens === 'number' ? draft.maxTokens : 800;
      const maxTokens = Number.isFinite(maxTokensRaw) ? Math.max(1, Math.round(maxTokensRaw)) : 800;
      const maxDocsPerCollectionRaw =
        typeof draft.maxDocsPerCollection === 'number' ? draft.maxDocsPerCollection : 400;
      const maxDocsPerCollection = Number.isFinite(maxDocsPerCollectionRaw)
        ? Math.max(10, Math.min(Math.round(maxDocsPerCollectionRaw), 2000))
        : 400;

      await upsert({
        ...(draft.id ? { id: draft.id } : {}),
        name,
        description: typeof draft.description === 'string' ? draft.description : null,
        llmModel,
        embeddingModel,
        systemPrompt: draft.systemPrompt ?? '',
        collectionIds: selectedCollectionIds,
        temperature,
        maxTokens,
        retrievalTopK: typeof draft.retrievalTopK === 'number' ? draft.retrievalTopK : 6,
        retrievalMinScore:
          typeof draft.retrievalMinScore === 'number' ? draft.retrievalMinScore : 0.15,
        maxDocsPerCollection,
      });
      toast(draft.id ? 'Learner agent updated.' : 'Learner agent created.', { variant: 'success' });
    } catch (error) {
      logClientError(error);
      toast(error instanceof Error ? error.message : 'Failed to save learner agent.', {
        variant: 'error',
      });
      throw error;
    }
  };

  const handleDelete = async (agent: LearnerAgentLibraryItem): Promise<void> => {
    try {
      await remove({ id: agent.id });
      toast('Learner agent deleted.', { variant: 'success' });
    } catch (error) {
      logClientError(error);
      toast(error instanceof Error ? error.message : 'Failed to delete learner agent.', {
        variant: 'error',
      });
      throw error;
    }
  };

  return (
    <ItemLibrary<LearnerAgentLibraryItem>
      title='Learner Agents'
      description='Agents that answer using connected embedding collections (RAG).'
      entityName='Learner Agent'
      items={libraryAgents}
      isLoading={isLoadingContext}
      isSaving={saving}
      onSave={handleSave}
      onDelete={handleDelete}
      backLink={
        <AdminAgentTeachingBreadcrumbs current='Agents' className='mb-2' />
      }
      buildDefaultItem={() => ({
        name: '',
        description: '',
        llmModel: chatModelId,
        embeddingModel: embeddingModelId,
        systemPrompt: '',
        collectionIds: [],
        temperature: 0.2,
        maxTokens: 800,
        retrievalTopK: 6,
        retrievalMinScore: 0.15,
        maxDocsPerCollection: 400,
      })}
      renderItemTags={(agent: LearnerAgentLibraryItem) => [
        `LLM: ${chatModelId || agent.llmModel || '—'}`,
        `Embed: ${embeddingModelId || agent.embeddingModel || '—'}`,
        `KB: ${(agent.collectionIds ?? []).length}`,
        `Temp: ${(typeof agent.temperature === 'number' ? agent.temperature : 0.2).toFixed(2)}`,
      ]}
      renderExtraFields={(
        draft: LearnerAgentLibraryItem,
        onChange: (changes: Partial<LearnerAgentLibraryItem>) => void
      ) => (
        <LearnerAgentForm
          draft={draft}
          onChange={onChange}
          chatModel={chatModelId}
          embeddingModel={embeddingModelId}
          collections={collections}
        />
      )}
    />
  );
}

'use client';

import React from 'react';

import {
  ContextRegistryPageProvider,
  useOptionalContextRegistryPageEnvelope,
  useRegisterContextRegistryPageSource,
} from '@/features/ai/ai-context-registry/context/page-context';
import type {
  AgentTeachingAgentRecord,
  AgentTeachingChatSource,
  AgentTeachingEmbeddingCollectionRecord,
} from '@/shared/contracts/agent-teaching';
import type { SimpleChatMessage } from '@/shared/contracts/chatbot';
import { AdminAgentTeachingBreadcrumbs } from '@/shared/ui/admin.public';
import { useToast } from '@/shared/ui/primitives.public';
import { PageLayout, UI_GRID_ROOMY_CLASSNAME } from '@/shared/ui/navigation-and-layout.public';

import { useAgentTeachingQueriesContext } from '../context/AgentTeachingContext';
import {
  AGENT_TEACHING_CHAT_CONTEXT_ROOT_IDS,
  buildAgentTeachingChatContextBundle,
} from '../context-registry/chat-page';
import { useTeachingChatMutation } from '../hooks/useAgentTeachingQueries';
import { logClientError } from '@/shared/utils/observability/client-error-logger';
import { AgentSidebar, ChatPane } from '../components/AgentTeachingChatComponents';

function AgentTeachingChatPageContent(): React.JSX.Element {
  const { toast } = useToast();
  const {
    agents,
    collections,
    chatModelId,
    embeddingModelId,
    isLoading: loadingAgents,
  } = useAgentTeachingQueriesContext();
  const chatMutation = useTeachingChatMutation();
  const contextRegistry = useOptionalContextRegistryPageEnvelope();

  const [selectedAgentId, setSelectedAgentId] = React.useState<string>('');
  const [input, setInput] = React.useState('');
  const [messages, setMessages] = React.useState<SimpleChatMessage[]>([]);
  const [lastSources, setLastSources] = React.useState<AgentTeachingChatSource[]>([]);

  const sending = chatMutation.isPending;

  const selectedAgent = React.useMemo(
    () =>
      selectedAgentId.length > 0
        ? (agents.find((a: AgentTeachingAgentRecord) => a.id === selectedAgentId) ?? null)
        : null,
    [agents, selectedAgentId]
  );

  const registrySource = React.useMemo(
    () => ({
      label: 'Agent Teaching Chat',
      resolved: buildAgentTeachingChatContextBundle({
        agents,
        collections,
        chatModelId,
        embeddingModelId,
        selectedAgent,
        messages,
        lastSources,
      }),
    }),
    [agents, chatModelId, collections, embeddingModelId, lastSources, messages, selectedAgent]
  );

  useRegisterContextRegistryPageSource('agent-teaching-chat-state', registrySource);

  const resolveCollectionName = (id: string): string => {
    const found = collections.find((c: AgentTeachingEmbeddingCollectionRecord) => c.id === id);
    return found?.name ?? id;
  };

  const handleSend = async (): Promise<void> => {
    if (selectedAgentId.length === 0) {
      toast('Select a learner agent first.', { variant: 'error' });
      return;
    }
    const content = input.trim();
    if (content.length === 0) return;

    const nextMessages: SimpleChatMessage[] = [...messages, { role: 'user', content }];
    setMessages(nextMessages);
    setInput('');
    setLastSources([]);

    try {
      const data = await chatMutation.mutateAsync({
        agentId: selectedAgentId,
        messages: nextMessages,
        contextRegistry,
      });
      setMessages((prev) => [...prev, { role: 'assistant', content: data.message }]);
      setLastSources(Array.isArray(data.sources) ? data.sources : []);
    } catch (error) {
      logClientError(error);
      toast(error instanceof Error ? error.message : 'Chat failed.', { variant: 'error' });
      setMessages((prev) => [
        ...prev,
        { role: 'assistant', content: 'Error: failed to generate response.' },
      ]);
    }
  };

  return (
    <PageLayout
      title='Learner Chat'
      eyebrow={<AdminAgentTeachingBreadcrumbs current='Chat' className='mb-2' />}
      description='Chat with a learner agent. The response is generated with retrieved embedded sources.'
    >
      <div className={`${UI_GRID_ROOMY_CLASSNAME} lg:grid-cols-3`}>
        <AgentSidebar
          agents={agents}
          loadingAgents={loadingAgents}
          selectedAgentId={selectedAgentId}
          setSelectedAgentId={setSelectedAgentId}
          resolveCollectionName={resolveCollectionName}
          setMessages={setMessages}
          setLastSources={setLastSources}
        />

        <ChatPane
          selectedAgent={selectedAgent}
          messages={messages}
          setMessages={setMessages}
          lastSources={lastSources}
          setLastSources={setLastSources}
          sending={sending}
          input={input}
          setInput={setInput}
          handleSend={() => {
            void handleSend();
          }}
          resolveCollectionName={resolveCollectionName}
        />
      </div>
    </PageLayout>
  );
}

export function AgentTeachingChatPage(): React.JSX.Element {
  return (
    <ContextRegistryPageProvider
      pageId='agentcreator:teaching-chat'
      title='Agent Creator Teaching Chat'
      rootNodeIds={[...AGENT_TEACHING_CHAT_CONTEXT_ROOT_IDS]}
    >
      <AgentTeachingChatPageContent />
    </ContextRegistryPageProvider>
  );
}

'use client';

import { Trash2, BookOpen } from 'lucide-react';
import React, { useMemo } from 'react';

import type { AgentTeachingEmbeddingDocumentListItem } from '@/shared/contracts/agent-teaching';
import { AdminAgentTeachingBreadcrumbs } from '@/shared/ui/admin.public';
import { Button, Badge } from '@/shared/ui/primitives.public';
import { StandardDataTablePanel, ConfirmModal, PanelHeader } from '@/shared/ui/templates.public';
import { UI_GRID_ROOMY_CLASSNAME } from '@/shared/ui/navigation-and-layout.public';

import { DocumentAddForm } from '../components/DocumentAddForm';
import { SearchSimulator } from '../components/SearchSimulator';
import { useAgentTeachingCollectionDetailState } from '../hooks/useAgentTeachingCollectionDetailState';

import type { ColumnDef } from '@tanstack/react-table';

const hasText = (value: string | null | undefined): value is string =>
  value !== null && value !== undefined && value.length > 0;

const hasTags = (tags: string[] | null | undefined): tags is string[] =>
  tags !== null && tags !== undefined && tags.length > 0;

const formatUpdatedAt = (value: string | null | undefined): string => {
  if (!hasText(value)) {
    return '—';
  }
  return new Date(value).toLocaleString();
};

const buildDocumentColumns = ({
  adding,
  deleting,
  setDocToDelete,
}: Pick<
  ReturnType<typeof useAgentTeachingCollectionDetailState>,
  'adding' | 'deleting' | 'setDocToDelete'
>): ColumnDef<AgentTeachingEmbeddingDocumentListItem>[] => [
  {
    accessorKey: 'text',
    header: 'Document Text',
    cell: ({ row }) => (
      <div className='max-w-[520px] truncate text-sm text-gray-300' title={row.original.text}>
        {row.original.text}
      </div>
    ),
  },
  {
    id: 'meta',
    header: 'Metadata',
    cell: ({ row }) => <DocumentMetadataCell document={row.original} />,
  },
  {
    accessorKey: 'updatedAt',
    header: 'Updated',
    cell: ({ row }) => (
      <span className='text-xs text-gray-500'>{formatUpdatedAt(row.original.updatedAt)}</span>
    ),
  },
  {
    id: 'actions',
    header: () => <div className='text-right'>Actions</div>,
    cell: ({ row }) => (
      <DocumentActions
        document={row.original}
        disabled={adding || deleting}
        onDelete={setDocToDelete}
      />
    ),
  },
];

function DocumentMetadataCell({
  document,
}: {
  document: AgentTeachingEmbeddingDocumentListItem;
}): React.JSX.Element {
  return (
    <div className='flex flex-col gap-1 text-xs'>
      {hasText(document.metadata?.title) ? (
        <div className='text-gray-200 font-medium'>{document.metadata.title}</div>
      ) : null}
      {hasText(document.metadata?.source) ? (
        <div className='text-gray-500 italic'>{document.metadata.source}</div>
      ) : null}
      {hasTags(document.metadata?.tags) ? (
        <div className='flex gap-1 flex-wrap'>
          {document.metadata.tags.map((tag) => (
            <Badge key={tag} variant='outline' className='text-[9px] px-1 py-0'>
              {tag}
            </Badge>
          ))}
        </div>
      ) : null}
      <div className='text-[10px] text-gray-600 mt-1'>
        {document.embeddingModel} ({document.embeddingDimensions})
      </div>
    </div>
  );
}

function DocumentActions({
  document,
  disabled,
  onDelete,
}: {
  document: AgentTeachingEmbeddingDocumentListItem;
  disabled: boolean;
  onDelete: (document: AgentTeachingEmbeddingDocumentListItem | null) => void;
}): React.JSX.Element {
  return (
    <div className='text-right'>
      <Button
        variant='ghost'
        size='xs'
        className='h-7 w-7 p-0 text-rose-400 hover:text-rose-300'
        onClick={() => onDelete(document)}
        disabled={disabled}
        aria-label={`Delete ${document.metadata?.title ?? 'document'}`}
        title='Delete document'
      >
        <Trash2 className='size-3.5' />
      </Button>
    </div>
  );
}

type CollectionDetailState = ReturnType<typeof useAgentTeachingCollectionDetailState>;

const getCollectionName = (collection: CollectionDetailState['collection']): string =>
  collection.name;

const buildCollectionActions = (
  collection: CollectionDetailState['collection']
