function CollectionDetailTools({
  state,
  onAdd,
  onSearch,
}: {
  state: CollectionDetailState;
  onAdd: () => void;
  onSearch: () => void;
}): React.JSX.Element {
  return (
    <div className={`${UI_GRID_ROOMY_CLASSNAME} lg:grid-cols-2`}>
